import TextField from '@beetrack/hp-text-field-react'
import '@beetrack/hp-text-field-style'

// Default
<TextField
  label='Label'
  value={value}
  onChange={e => setValue(e.target.value)}
/>

// Required + helper
<TextField
  label='Nombre'
  value={value}
  required
  helperText='Aparecerá en órdenes y reportes'
  onChange={e => setValue(e.target.value)}
/>

// Error state
<TextField
  label='Email'
  value={value}
  error
  helperText='Formato de email inválido'
  trailingIcon={<XCircle />}
/>

// Dense + trailing icon
<TextField
  label='Buscar'
  dense
  trailingIcon={<Search />}
  onChange={e => setValue(e.target.value)}
/>

// TextArea
<TextField
  label='Notas de entrega'
  textArea
  rows='4'
  value={value}
  onChange={e => setValue(e.target.value)}
/>

// Disabled
<TextField label='Label' value='Valor bloqueado' disabled />

// Dark
<TextField label='Label' dark />

// Read only
<TextField label='ID de orden' value='ORD-001' readOnly />
